// src/store/index.js
import { createStore } from 'vuex'

// 创建一个新的 store 实例
const store = createStore({
  state() {
    return {
      posts: [
        {
          id: 1,
          title: '欢迎来到我的博客',
          date: '2024年11月1日',
          summary: '这是我的第一篇博客文章。你可以在这里使用 Markdown 语法。',
          content: `
# 欢迎来到我的博客

这是我的第一篇博客文章。你可以在这里使用 Markdown 语法：

## 数学公式示例

\`\`\`math
E = mc^2
\`\`\`

## 代码块示例

\`\`\`python
def hello_world():
    print("Hello, World!")
\`\`\`
          `
        },
        {
          id: 2,
          title: '第二篇文章',
          date: '2024年11月1日',
          summary: '大数据实验报告与深度学习的探索。',
          content: `
# 大数据的实验报告

写着写着写飞了，已经写成深度学习报告了。

## 神经网络公式

\`\`\`math
f(x) = \frac{1}{1 + e^{-x}}
\`\`\`

## 示例代码

\`\`\`python
import tensorflow as tf

model = tf.keras.Sequential([
    tf.keras.layers.Dense(128, activation='relu'),
    tf.keras.layers.Dense(10, activation='softmax')
])
\`\`\`
          `
        }
      ]
    }
  },
  getters: {
    getPostById: (state) => (id) => {
      return state.posts.find(post => post.id === parseInt(id))
    },
    getAllPosts: (state) => {
      return state.posts
    }
  },
  mutations: {
    ADD_POST(state, post) {
      state.posts.push({
        ...post,
        id: state.posts.length + 1,
        date: new Date().toLocaleDateString('zh-CN')
      })
    },
    UPDATE_POST(state, { id, post }) {
      const index = state.posts.findIndex(p => p.id === id)
      if (index !== -1) {
        state.posts[index] = { ...state.posts[index], ...post }
      }
    },
    DELETE_POST(state, id) {
      state.posts = state.posts.filter(post => post.id !== id)
    }
  },
  actions: {
    addPost({ commit }, post) {
      commit('ADD_POST', post)
    },
    updatePost({ commit }, payload) {
      commit('UPDATE_POST', payload)
    },
    deletePost({ commit }, id) {
      commit('DELETE_POST', id)
    }
  }
})

export default store
