<!-- src/components/BlogPost.vue -->
<template>
    <article class="blog-post">
      <h2 class="post-title">
        <a href="#" @click.prevent="$emit('click')">{{ post.title }}</a>
      </h2>
      <div class="post-date">{{ post.date }}</div>
      <div class="post-content">
        <p>{{ post.summary }}</p>
      </div>
    </article>
  </template>
  
  <script>
  export default {
    name: 'BlogPostItem',
    props: {
      post: {
        type: Object,
        required: true
      }
    }
  }
  </script>
  
  
  
